import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const h=JSON.parse('{"title":"13、死神【XIII】","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/2.改造与功法/改造/4.综合类/替身/阿尔卡纳/13、死神【XIII】.md","filePath":"4.资源分区/2.改造与功法/改造/4.综合类/替身/阿尔卡纳/13、死神【XIII】.md"}'),p={name:"4.资源分区/2.改造与功法/改造/4.综合类/替身/阿尔卡纳/13、死神【XIII】.md"};function d(i,a,_,l,I,c){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"_13、死神【xiii】",tabindex:"-1"},[s("13、死神【XIII】 "),e("a",{class:"header-anchor",href:"#_13、死神【xiii】","aria-label":'Permalink to "13、死神【XIII】"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘")])])],-1),o('<h1 id="死神" tabindex="-1">死神 <a class="header-anchor" href="#死神" aria-label="Permalink to &quot;死神&quot;">​</a></h1><p>死神13</p><p>S+9600<br> 替身外貌：<br> 死神13的外貌如同真正的死神一般，有着小丑面具般的脸部，头戴紫色高帽，身披深紫色披风，穿着金色的胸甲和臂铠，手持一把巨大的死神镰刀。替身可以漂浮在空中，斗篷之下藏着的身体并不具备下半身，可以说组成死神13主体的只有上半身以及镰刀。</p><p>替身数据：<br> 破坏力C<br> 速度C（闪避防御）<br> 射程E<br> 持续力B<br> 精密动作性D<br> 成长性B</p><p>替身对应主属性：决心</p><p>替身能力：<br> 梦中恶魇：死神13是只能具现在的梦中的替身，无法在现实里出现。</p><p>梦中恶灵：替身使者能以一个标准动作控制死神13能将射程范围内所有陷入睡眠状态的目标拉入梦境，目标以意志豁免对抗替身使者的替身使用检定，不造成伤害，对抗失败会被死神13拉入一个如同游乐场般的梦境场景。此时替身使者能以一个标准动作让死神13梦境中控制梦境中的一切对梦境内的目标进行攻击，并且由于死神13能控制梦境中的一切所以其替身使用检定在此时会获得【决心×13】点环境加值，目标需要以意志豁免防御，并且此时目标的意志豁免会承受【决心上附加数×13】点环境减值，承受未豁免数的伤害，在梦境所造成的伤害会在醒来后完全地反馈到肉体身上，并且也不会因为梦境中的伤害醒来，只有睡眠因为自然解除或受到伤害解除才能脱离梦境，脱离梦境前需要目标以意志豁免对抗替身使者的替身使用检定，不造成伤害，对抗失败会忘记梦中的一切记忆，此外如果在梦境中的意志豁免超过替身使用检定一倍可以在梦中反杀死神13，死神13及其替身使者将会受到差额点伤害。以上效果中，将目标拉入梦境并对其攻击是一个S级心灵来源的即死效果，阻止目标因为梦境内的伤害醒来是一个S级心灵来源的睡眠效果，使目标遗忘梦中的一切记忆是一个S级心灵来源的思维控制效果。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',9)])])}const f=r(p,[["render",d]]);export{h as __pageData,f as default};
